def compute_file_hash(filepath: str, algorithm: str = "sha256") -> str:
    """Compute cryptographic hash of a file."""
    h = hashlib.new(algorithm)
    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(8192)
            if not chunk:
                break
            h.update(chunk)
    return h.hexdigest()


def compute_bytes_hash(data: bytes, algorithm: str = "sha256") -> str:
    """Compute cryptographic hash of bytes."""
    h = hashlib.new(algorithm)
    h.update(data)
    return h.hexdigest()


def verify_checksum(filepath: str, expected_hash: str, algorithm: str = "sha256") -> bool:
    """Verify file integrity using cryptographic hash."""
    actual_hash = compute_file_hash(filepath, algorithm)
    return actual_hash == expected_hash


def scan_state_dict_for_backdoors(state_dict: Dict[str, Any]) -> List[str]:
    """
    Scan a model state dict for potential backdoor indicators.

    Checks for:
    - Unexpected non-tensor objects that could contain malicious code
    - Suspiciously named keys that don't follow standard naming conventions
    - Abnormal weight statistics that might indicate trigger patterns
    """
    warnings = []

    for key, value in state_dict.items():
        # Check 1: All values should be tensors in a legitimate state dict
        if not isinstance(value, torch.Tensor):
            warnings.append(
                f"Non-tensor value found for key '{key}': type={type(value).__name__}. "
                f"This could indicate embedded malicious objects."
            )
            continue

        # Check 2: Look for suspiciously named parameters
        suspicious_prefixes = ["backdoor", "trigger", "trojan", "payload", "exploit"]
        key_lower = key.lower()
        for prefix in suspicious_prefixes:
            if prefix in key_lower:
                warnings.append(
                    f"Suspiciously named parameter: '{key}'"
                )

        # Check 3: Check for abnormal weight statistics
        if value.numel() > 0 and value.is_floating_point():
            # Check for NaN or Inf values
            if torch.isnan(value).any():
                warnings.append(f"NaN values found in parameter '{key}'")
            if torch.isinf(value).any():
                warnings.append(f"Inf values found in parameter '{key}'")

            # Check for extremely large values that might indicate manipulation
            max_abs = value.abs().max().item()
            if max_abs > 1e6:
                warnings.append(
                    f"Extremely large values in parameter '{key}': max_abs={max_abs:.2e}"
                )

    return warnings


def validate_model_architecture(
    loaded_state_dict: Dict[str, Any],
    reference_model: nn.Module,
    strict: bool = True
) -> Tuple[bool, List[str]]:
    """
    Validate that loaded state dict matches expected model architecture.

    This prevents attacks where adversaries modify the model architecture
    to include hidden backdoor layers.
    """
    issues = []
    reference_keys = set(reference_model.state_dict().keys())
    loaded_keys = set(loaded_state_dict.keys())

    # Check for unexpected extra keys
    extra_keys = loaded_keys - reference_keys
    if extra_keys:
        issues.append(
            f"Unexpected extra parameters found (possible hidden layers): {extra_keys}"
        )

    # Check for missing keys
    missing_keys = reference_keys - loaded_keys
    if missing_keys and strict:
        issues.append(f"Missing expected parameters: {missing_keys}")

    # Check shape compatibility
    for key in reference_keys & loaded_keys:
        expected_shape = reference_model.state_dict()[key].shape
        loaded_shape = loaded_state_dict[key].shape
        if expected_shape != loaded_shape:
            issues.append(
                f"Shape mismatch for '{key}': expected {expected_shape}, got {loaded_shape}"
            )

    is_valid = len(issues) == 0
    return is_valid, issues


def spectral_signature_analysis(
    model: nn.Module,
    clean_data_loader: DataLoader,
    num_samples: int = 100
) -> Dict[str, float]:
    """
    Perform spectral signature analysis to detect potential backdoor triggers.

    Based on the paper "Spectral Signatures in Backdoor Attacks"
    (Tran et al., NeurIPS 2018).

    Returns anomaly scores for each class.
    """
    model.eval()
    representations = {}

    with torch.no_grad():
        count = 0
        for inputs, labels in clean_data_loader:
            if count >= num_samples:
                break

            # Get intermediate representations (before final layer)
            features = _extract_features(model, inputs)

            for i, label in enumerate(labels):
                label_item = label.item()
                if label_item not in representations:
                    representations[label_item] = []
                representations[label_item].append(features[i].cpu())

            count += len(inputs)

    anomaly_scores = {}
    for label, reps in representations.items():
        if len(reps) < 2:
            continue
        rep_matrix = torch.stack(reps)
        # Center the representations
        mean_rep = rep_matrix.mean(dim=0)
        centered = rep_matrix - mean_rep

        # Compute SVD
        try:
            _, S, _ = torch.svd(centered)
            # The ratio of the top singular value to the sum indicates
            # potential backdoor presence
            if S.sum() > 0:
                anomaly_scores[label] = (S[0] / S.sum()).item()
            else:
                anomaly_scores[label] = 0.0
        except Exception:
            anomaly_scores[label] = 0.0

    return anomaly_scores


def _extract_features(model: nn.Module, inputs: torch.Tensor) -> torch.Tensor:
    """Extract features from the penultimate layer of a model."""
    features = []

    def hook_fn(module, input, output):
        features.append(output.detach())

    # Find the last layer before the classifier
    modules = list(model.children())
    if len(modules) > 1:
        # Hook into the second-to-last module
        hook = modules[-2].register_forward_hook(hook_fn)
    else:
        hook = modules[-1].register_forward_hook(hook_fn)

    with torch.no_grad():
        model(inputs)

    hook.remove()

    if features:
        feat = features[0]
        if feat.dim() > 2:
            feat = feat.view(feat.size(0), -1)
        return feat
    return inputs.view(inputs.size(0), -1)


