class SecureModelLoader:
    """
    Securely downloads and loads pretrained model checkpoints.

    Security measures:
    1. Uses weights_only=True for torch.load to prevent arbitrary code execution
    2. Verifies file checksums against known good values
    3. Scans state dicts for suspicious content
    4. Validates architecture compatibility
    """

    def __init__(
        self,
        cache_dir: Optional[str] = None,
        trusted_registry: Optional[Dict] = None
    ):
        self.cache_dir = cache_dir or os.path.join(
            tempfile.gettempdir(), "secure_model_cache"
        )
        os.makedirs(self.cache_dir, exist_ok=True)
        self.trusted_registry = trusted_registry or TRUSTED_MODEL_REGISTRY

    def download_model(
        self,
        url: str,
        expected_hash: Optional[str] = None,
        filename: Optional[str] = None
    ) -> str:
        """
        Download a model file with integrity verification.
        """
        if filename is None:
            filename = url.split("/")[-1]

        filepath = os.path.join(self.cache_dir, filename)

        # Check if already cached and valid
        if os.path.exists(filepath) and expected_hash:
            if verify_checksum(filepath, expected_hash):
                logger.info(f"Using cached model: {filepath} (checksum verified)")
                return filepath
            else:
                logger.warning("Cached file checksum mismatch, re-downloading...")
                os.remove(filepath)

        # Download using torch.hub (which uses urllib internally)
        logger.info(f"Downloading model from: {url}")
        torch.hub.download_url_to_file(url, filepath, progress=True)

        # Verify checksum after download
        if expected_hash:
            if not verify_checksum(filepath, expected_hash):
                os.remove(filepath)
                raise ChecksumMismatchError(
                    f"Downloaded file checksum does not match expected value. "
                    f"The file may have been tampered with."
                )
            logger.info("Checksum verification passed.")
        else:
            logger.warning(
                "No expected hash provided. Cannot verify file integrity. "
                "Consider adding the hash to the trusted registry."
            )

        return filepath

    def load_state_dict_secure(
        self,
        filepath: str,
        reference_model: Optional[nn.Module] = None,
        map_location: Optional[str] = None
    ) -> Dict[str, Any]:
        """
        Securely load a state dict from a file.

        CRITICAL SECURITY: Uses weights_only=True to prevent pickle-based
        arbitrary code execution attacks. This is the primary defense against
        model backdoors embedded via malicious pickle payloads.
        """
        logger.info(f"Loading state dict from: {filepath}")

        # SECURITY: weights_only=True prevents arbitrary code execution
        # via malicious pickle payloads. This is essential because torch.load
        # uses pickle by default, which can execute arbitrary Python code.
        try:
            state_dict = torch.load(
                filepath,
                map_location=map_location or "cpu",
                weights_only=True
            )
        except Exception as e:
            raise ModelSecurityError(
                f"Failed to load model with weights_only=True. "
                f"This may indicate the file contains non-tensor objects "
                f"or malicious code: {e}"
            )

        # If the loaded object is a full checkpoint dict, extract state_dict
        if isinstance(state_dict, dict) and "state_dict" in state_dict:
            state_dict = state_dict["state_dict"]
        elif isinstance(state_dict, dict) and "model_state_dict" in state_dict:
            state_dict = state_dict["model_state_dict"]

        # Scan for backdoor indicators
        warnings = scan_state_dict_for_backdoors(state_dict)
        if warnings:
            for w in warnings:
                logger.warning(f"SECURITY WARNING: {w}")
            raise SuspiciousModelError(
                f"Model failed security scan with {len(warnings)} warning(s). "
                f"Details: {warnings}"
            )

        # Validate architecture if reference model provided
        if reference_model is not None:
            is_valid, issues = validate_model_architecture(
                state_dict, reference_model, strict=False
            )
            if not is_valid:
                for issue in issues:
                    logger.warning(f"ARCHITECTURE WARNING: {issue}")
                raise SuspiciousModelError(
                    f"Model architecture validation failed: {issues}"
                )

        logger.info("State dict loaded and validated successfully.")
        return state_dict

    def load_from_registry(
        self,
        model_name: str,
        reference_model: Optional[nn.Module] = None,
        map_location: Optional[str] = None
    ) -> Dict[str, Any]:
        """Load a model from the trusted registry with full verification."""
        if model_name not in self.trusted_registry:
            raise ValueError(
                f"Model '{model_name}' not found in trusted registry. "
                f"Available models: {list(self.trusted_registry.keys())}"
            )

        entry = self.trusted_registry[model_name]
        filepath = self.download_model(
            url=entry["url"],
            expected_hash=entry.get("sha256")
        )

        return self.load_state_dict_secure(
            filepath,
            reference_model=reference_model,
            map_location=map_location
        )


