class SecureFineTuner:
    """
    Fine-tunes pretrained models on custom datasets with security measures.

    Security measures during fine-tuning:
    1. Neural Cleanse-inspired anomaly detection
    2. Weight perturbation analysis
    3. Gradient monitoring for suspicious patterns
    4. Output consistency checks
    """

    def __init__(
        self,
        model: nn.Module,
        num_classes: int,
        device: Optional[str] = None,
        learning_rate: float = 1e-3,
        freeze_backbone: bool = True
    ):
        self.device = device or ("cuda" if torch.cuda.is_available() else "cpu")
        self.model = model.to(self.device)
        self.num_classes = num_classes
        self.learning_rate = learning_rate
        self.freeze_backbone = freeze_backbone

        # Modify the final classification layer for the new task
        self._replace_classifier(num_classes)

        if freeze_backbone:
            self._freeze_backbone()

        self.optimizer = None
        self.criterion = nn.CrossEntropyLoss()
        self.training_history = []

    def _replace_classifier(self, num_classes: int):
        """Replace the final classifier layer for transfer learning."""
        # Handle common architectures
        if hasattr(self.model, 'fc'):
            in_features = self.model.fc.in_features
            self.model.fc = nn.Linear(in_features, num_classes)
        elif hasattr(self.model, 'classifier'):
            if isinstance(self.model.classifier, nn.Sequential):
                last_layer = self.model.classifier[-1]
                if isinstance(last_layer, nn.Linear):
                    in_features = last_layer.in_features
                    self.model.classifier[-1] = nn.Linear(in_features, num_classes)
            elif isinstance(self.model.classifier, nn.Linear):
                in_features = self.model.classifier.in_features
                self.model.classifier = nn.Linear(in_features, num_classes)
        elif hasattr(self.model, 'head'):
            if isinstance(self.model.head, nn.Linear):
                in_features = self.model.head.in_features
                self.model.head = nn.Linear(in_features, num_classes)
        else:
            logger.warning(
                "Could not automatically identify classifier layer. "
                "Please manually replace the classifier before fine-tuning."
            )

        self.model = self.model.to(self.device)

    def _freeze_backbone(self):
        """Freeze all layers except the classifier."""
        # First freeze everything
        for param in self.model.parameters():
            param.requires_grad = False

        # Unfreeze classifier
        if hasattr(self.model, 'fc'):
            for param in self.model.fc.parameters():
                param.requires_grad = True
        elif hasattr(self.model, 'classifier'):
            for param in self.model.classifier.parameters():
                param.requires_grad = True
        elif hasattr(self.model, 'head'):
            for param in self.model.head.parameters():
                param.requires_grad = True

    def _setup_optimizer(self):
        """Setup optimizer for trainable parameters only."""
        trainable_params = filter(
            lambda p: p.requires_grad, self.model.parameters()
        )
        self.optimizer = optim.Adam(trainable_params, lr=self.learning_rate)

    def fine_tune(
        self,
        train_loader: DataLoader,
        val_loader: Optional[DataLoader] = None,
        epochs: int = 10,
        early_stopping_patience: int = 3,
        gradient_clip_value: float = 1.0,
        monitor_backdoor: bool = True
    ) -> Dict[str, Any]:
        """
        Fine-tune the model with security monitoring.
        """
        self._setup_optimizer()
        best_val_acc = 0.0
        patience_counter = 0
        best_state_dict = None

        # Pre-training backdoor check
        if monitor_backdoor and val_loader is not None:
            logger.info("Running pre-training backdoor analysis...")
            pre_scores = spectral_signature_analysis(
                self.model, val_loader, num_samples=50
            )
            logger.info(f"Pre-training spectral scores: {pre_scores}")

            # Check for anomalous scores
            if pre_scores:
                max_score = max(pre_scores.values())
                if max_score > 0.9:
                    logger.warning(
                        f"HIGH ANOMALY SCORE DETECTED ({max_score:.4f}). "
                        f"The pretrained model may contain a backdoor."
                    )

        for epoch in range(epochs):
            # Training phase
            train_loss, train_acc = self._train_epoch(
                train_loader, gradient_clip_value
            )

            # Validation phase
            val_loss, val_acc = 0.0, 0.0
            if val_loader is not None:
                val_loss, val_acc = self._validate(val_loader)

            epoch_info = {
                "epoch": epoch + 1,
                "train_loss": train_loss,
                "train_acc": train_acc,
                "val_loss": val_loss,
                "val_acc": val_acc,
            }
            self.training_history.append(epoch_info)

            logger.info(
                f"Epoch {epoch + 1}/{epochs} - "
                f"Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.4f}, "
                f"Val Loss: {val_loss:.4f}, Val Acc: {val_acc:.4f}"
            )

            # Early stopping
            if val_loader is not None:
                if val_acc > best_val_acc:
                    best_val_acc = val_acc
                    best_state_dict = {
                        k: v.clone() for k, v in self.model.state_dict().items()
                    }
                    patience_counter = 0
                else:
                    patience_counter += 1
                    if patience_counter >= early_stopping_patience:
                        logger.info(
                            f"Early stopping at epoch {epoch + 1}"
                        )
                        break

        # Restore best model
        if best_state_dict is not None:
            self.model.load_state_dict(best_state_dict)

        # Post-training backdoor check
        if monitor_backdoor and val_loader is not None:
            logger.info("Running post-training backdoor analysis...")
            post_scores = spectral_signature_analysis(
                self.model, val_loader, num_samples=50
            )
            logger.info(f"Post-training spectral scores: {post_scores}")

        return {
            "best_val_acc": best_val_acc,
            "training_history": self.training_history,
        }

    def _train_epoch(
        self,
        train_loader: DataLoader,
        gradient_clip_value: float
    ) -> Tuple[float, float]:
        """Train for one epoch with gradient monitoring."""
        self.model.train()
        total_loss = 0.0
        correct = 0
        total = 0
        gradient_norms = []

        for batch_idx, (inputs, targets) in enumerate(train_loader):
            inputs, targets = inputs.to(self.device), targets.to(self.device)

            self.optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = self.criterion(outputs, targets)
            loss.backward()

            # Gradient clipping to prevent gradient-based attacks
            total_norm = torch.nn.utils.clip_grad_norm_(
                self.model.parameters(), gradient_clip_value
            )
            gradient_norms.append(total_norm.item() if isinstance(total_norm, torch.Tensor) else total_norm)

            self.optimizer.step()

            total_loss += loss.item()
            _, predicted = outputs.max(1)
            total += targets.size(0)
            correct += predicted.eq(targets).sum().item()

        # Monitor gradient norms for anomalies
        if gradient_norms:
            avg_norm = sum(gradient_norms) / len(gradient_norms)
            max_norm = max(gradient_norms)
            if max_norm > 10 * avg_norm and avg_norm > 0:
                logger.warning(
                    f"Suspicious gradient spike detected: "
                    f"max={max_norm:.4f}, avg={avg_norm:.4f}"
                )

        avg_loss = total_loss / len(train_loader) if len(train_loader) > 0 else 0
        accuracy = correct / total if total > 0 else 0
        return avg_loss, accuracy

    def _validate(self, val_loader: DataLoader) -> Tuple[float, float]:
        """Validate the model."""
        self.model.eval()
        total_loss = 0.0
        correct = 0
        total = 0

        with torch.no_grad():
            for inputs, targets in val_loader:
                inputs, targets = inputs.to(self.device), targets.to(self.device)
                outputs = self.model(inputs)
                loss = self.criterion(outputs, targets)

                total_loss += loss.item()
                _, predicted = outputs.max(1)
                total += targets.size(0)
                correct += predicted.eq(targets).sum().item()

        avg_loss = total_loss / len(val_loader) if len(val_loader) > 0 else 0
        accuracy = correct / total if total > 0 else 0
        return avg_loss, accuracy

    def save_model_secure(
        self,
        filepath: str,
        metadata: Optional[Dict] = None
    ) -> str:
        """
        Save the fine-tuned model with integrity metadata.
        """
        save_dict = {
            "model_state_dict": self.model.state_dict(),
            "num_classes": self.num_classes,
            "training_history": self.training_history,
        }

        if metadata:
            save_dict["metadata"] = metadata

        torch.save(save_dict, filepath)

        # Compute and save checksum
        file_hash = compute_file_hash(filepath)
        hash_filepath = filepath + ".sha256"
        with open(hash_filepath, "w") as f:
            f.write(file_hash)

        logger.info(f"Model saved to {filepath}")
        logger.info(f"SHA256: {file_hash}")

        return file_hash


