def run_secure_transfer_learning_pipeline(
    model_name: str = "resnet18",
    num_classes: int = 10,
    epochs: int = 5,
    batch_size: int = 32,
    learning_rate: float = 1e-3,
    use_synthetic_data: bool = True,
    custom_train_dataset: Optional[Dataset] = None,
    custom_val_dataset: Optional[Dataset] = None,
    output_path: str = "fine_tuned_model.pth"
):
    """
    Complete secure transfer learning pipeline.
    """
    logger.info("=" * 60)
    logger.info("SECURE TRANSFER LEARNING PIPELINE")
    logger.info("=" * 60)

    # Step 1: Initialize secure model loader
    logger.info("\n[Step 1] Initializing secure model loader...")
    loader = SecureModelLoader()

    # Step 2: Create reference model architecture
    logger.info("\n[Step 2] Creating reference model architecture...")
    try:
        import torchvision.models as models
        if model_name == "resnet18":
            reference_model = models.resnet18(weights=None)
        elif model_name == "resnet50":
            reference_model = models.resnet50(weights=None)
        else:
            logger.info(f"Using torchvision to create {model_name}")
            model_fn = getattr(models, model_name, None)
            if model_fn is None:
                raise ValueError(f"Unknown model: {model_name}")
            reference_model = model_fn(weights=None)
    except ImportError:
        logger.warning("torchvision not available, creating simple model")
        reference_model = nn.Sequential(
            nn.Flatten(),
            nn.Linear(3 * 224 * 224, 512),
            nn.ReLU(),
            nn.Linear(512, 1000),
        )
        reference_model.fc = nn.Linear(512, 1000)

    # Step 3: Download and securely load pretrained weights
    logger.info("\n[Step 3] Downloading and loading pretrained weights...")
    try:
        if model_name in loader.trusted_registry:
            state_dict = loader.load_from_registry(
                model_name,
                reference_model=reference_model,
                map_location="cpu"
            )
        else:
            logger.warning(
                f"Model '{model_name}' not in trusted registry. "
                f"Using torchvision's built-in loading with verification."
            )
            # Fall back to torchvision's pretrained weights
            import torchvision.models as models
            if model_name == "resnet18":
                pretrained_model = models.resnet18(
                    weights=models.ResNet18_Weights.DEFAULT
                )
            elif model_name == "resnet50":
                pretrained_model = models.resnet50(
                    weights=models.ResNet50_Weights.DEFAULT
                )
            else:
                model_fn = getattr(models, model_name)
                pretrained_model = model_fn(pretrained=True)
            state_dict = pretrained_model.state_dict()

        # Load weights into reference model
        reference_model.load_state_dict(state_dict, strict=True)
        logger.info("Pretrained weights loaded successfully.")

    except (ChecksumMismatchError, SuspiciousModelError) as e:
        logger.error(f"SECURITY ALERT: {e}")
        logger.error("Aborting pipeline due to security concerns.")
        raise
    except Exception as e:
        logger.warning(f"Could not load pretrained weights: {e}")
        logger.info("Proceeding with randomly initialized model.")

    # Step 4: Prepare datasets
    logger.info("\n[Step 4] Preparing datasets...")
    if use_synthetic_data:
        full_dataset = SyntheticDataset(
            num_samples=500, num_classes=num_classes
        )
        train_size = int(0.8 * len(full_dataset))
        val_size = len(full_dataset) - train_size
        train_dataset, val_dataset = random_split(
            full_dataset, [train_size, val_size]
        )
    else:
        if custom_train_dataset is None:
            raise ValueError("custom_train_dataset required when use_synthetic_data=False")
        train_dataset = custom_train_dataset
        val_dataset = custom_val_dataset

    train_loader = DataLoader(
        train_dataset, batch_size=batch_size, shuffle=True, num_workers=0
    )
    val_loader = None
    if val_dataset is not None:
        val_loader = DataLoader(
            val_dataset, batch_size=batch_size, shuffle=False, num_workers=0
        )

    # Step 5: Initialize secure fine-tuner
    logger.info("\n[Step 5] Initializing secure fine-tuner...")
    fine_tuner = SecureFineTuner(
        model=reference_model,
        num_classes=num_classes,
        learning_rate=learning_rate,
        freeze_backbone=True
    )

    # Step 6: Fine-tune with security monitoring
    logger.info("\n[Step 6] Fine-tuning with security monitoring...")
    results = fine_tuner.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        epochs=epochs,
        early_stopping_patience=3,
        gradient_clip_value=1.0,
        monitor_backdoor=True
    )

    logger.info(f"\nFine-tuning complete. Best validation accuracy: {results['best_val_acc']:.4f}")

    # Step 7: Save the fine-tuned model securely
    logger.info("\n[Step 7] Saving fine-tuned model...")
    file_hash = fine_tuner.save_model_secure(
        output_path,
        metadata={
            "base_model": model_name,
            "num_classes": num_classes,
            "epochs_trained": len(results["training_history"]),
            "best_val_acc": results["best_val_acc"],
        }
    )

    logger.info("\n" + "=" * 60)
    logger.info("PIPELINE COMPLETE")
    logger.info(f"Model saved to: {output_path}")
    logger.info(f"Model hash: {file_hash}")
    logger.info("=" * 60)

    return results


# =============================================================================
# Verification utility for loading saved models
# =============================================================================

def load_fine_tuned_model_secure(
    filepath: str,
    model_class: type,
    num_classes: int,
    expected_hash: Optional[str] = None,
    **model_kwargs
) -> nn.Module:
    """
    Securely load a previously fine-tuned model.
    """
    # Verify integrity
    if expected_hash:
        if not verify_checksum(filepath, expected_hash):
            raise ChecksumMismatchError(
                "Model file has been modified since it was saved."
            )
        logger.info("File integrity verified.")
    else:
        # Try to load hash from companion file
        hash_filepath = filepath + ".sha256"
        if os.path.exists(hash_filepath):
            with open(hash_filepath, "r") as f:
                stored_hash = f.read().strip()
            if not verify_checksum(filepath, stored_hash):
                raise ChecksumMismatchError(
                    "Model file has been modified since it was saved."
                )
            logger.info("File integrity verified using companion hash file.")

    # Load with weights_only=True for security
    checkpoint = torch.load(filepath, map_location="cpu", weights_only=True)

    # Create model instance
    model = model_class(**model_kwargs)

    # Replace classifier if needed
    if hasattr(model, 'fc'):
        in_features = model.fc.in_features
        model.fc = nn.Linear(in_features, num_classes)
    elif hasattr(model, 'classifier'):
        if isinstance(model.classifier, nn.Sequential):
            last_layer = model.classifier[-1]
            if isinstance(last_layer, nn.Linear):
                in_features = last_layer.in_features
                model.classifier[-1] = nn.Linear(in_features, num_classes)

    # Load state dict
    state_dict = checkpoint.get("model_state_dict", checkpoint)
    model.load_state_dict(state_dict)

    logger.info("Fine-tuned model loaded securely.")
    return model


